CREATE TABLE process_to_business_unit_used
(
	id serial,
	process_id integer NOT NULL,
	business_unit_id integer DEFAULT NULL,
	CONSTRAINT pk_process_to_business_unit_used PRIMARY KEY (id)
	, CONSTRAINT fk_process_to_business_unit_used_to_process FOREIGN KEY (process_id) REFERENCES process (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_process_to_business_unit_used_to_business_unit FOREIGN KEY (business_unit_id) REFERENCES business_units (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_process_to_business_unit_used_process ON process_to_business_unit_used (process_id);
CREATE INDEX i_process_to_business_unit_used_business_unit ON process_to_business_unit_used (business_unit_id);
